import Vue from 'vue';
import Router from 'vue-router';
import store from '../store';

Vue.use(Router);

const router = new Router({
  mode: 'history',
  routes: [
    {
      path: '/',
      name: 'Home',
      component: () => import('../views/Home.vue'),
      meta: { title: '首页' }
    },
    {
      path: '/login',
      name: 'Login',
      component: () => import('../views/Login.vue'),
      meta: { title: '登录', noAuth: true }
    },
    {
      path: '/register',
      name: 'Register',
      component: () => import('../views/Register.vue'),
      meta: { title: '注册', noAuth: true }
    },
    {
      path: '/profile',
      name: 'Profile',
      component: () => import('../views/Profile.vue'),
      meta: { title: '个人中心', requiresAuth: true }
    },
    {
      path: '/code-review',
      name: 'CodeReview',
      component: () => import('../views/CodeReview.vue'),
      meta: { title: '代码审查', requiresAuth: true }
    },
    {
      path: '/code-review/:id',
      name: 'CodeReviewDetail',
      component: () => import('../views/CodeReviewDetail.vue'),
      meta: { title: '审查详情', requiresAuth: true }
    },
    {
      path: '/qa',
      name: 'QaHome',
      component: () => import('../views/QaHome.vue'),
      meta: { title: '智能问答', requiresAuth: true }
    },
    {
      path: '/qa/:id',
      name: 'QaDetail',
      component: () => import('../views/QaDetail.vue'),
      meta: { title: '问答详情', requiresAuth: true }
    },
    {
      path: '/learning-paths',
      name: 'LearningPaths',
      component: () => import('../views/LearningPaths.vue'),
      meta: { title: '学习路径' }
    },
    {
      path: '/learning-paths/:id',
      name: 'LearningPathDetail',
      component: () => import('../views/LearningPathDetail.vue'),
      meta: { title: '路径详情' }
    },
    {
      path: '/course/:courseId',
      name: 'CourseView',
      component: () => import('../views/CourseView.vue'),
      meta: { title: '课程学习', requiresAuth: true }
    },
    {
      path: '/admin',
      component: () => import('../views/admin/AdminLayout.vue'),
      meta: { title: '后台管理', requiresAuth: true, requiresAdmin: true },
      children: [
        {
          path: '',
          name: 'AdminDashboard',
          component: () => import('../views/admin/Dashboard.vue'),
          meta: { title: '控制台' }
        },
        {
          path: 'users',
          name: 'AdminUsers',
          component: () => import('../views/admin/Users.vue'),
          meta: { title: '用户管理' }
        },
        {
          path: 'paths',
          name: 'AdminPaths',
          component: () => import('../views/admin/Paths.vue'),
          meta: { title: '路径管理' }
        },
        {
          path: 'tags',
          name: 'AdminTags',
          component: () => import('../views/admin/Tags.vue'),
          meta: { title: '标签管理' }
        },
        {
          path: 'config',
          name: 'AdminConfig',
          component: () => import('../views/admin/Config.vue'),
          meta: { title: '系统配置' }
        },
        {
          path: 'logs',
          name: 'AdminLogs',
          component: () => import('../views/admin/Logs.vue'),
          meta: { title: '操作日志' }
        }
      ]
    },
    {
      path: '*',
      name: 'NotFound',
      component: () => import('../views/NotFound.vue'),
      meta: { title: '404' }
    }
  ]
});

// 路由守卫
router.beforeEach((to, from, next) => {
  document.title = to.meta.title ? `${to.meta.title} - AI-Code` : 'AI-Code';

  const token = store.state.token || localStorage.getItem('token');
  const user = store.state.user || JSON.parse(localStorage.getItem('user') || 'null');

  // 需要认证的页面
  if (to.meta.requiresAuth && !token) {
    next({ name: 'Login', query: { redirect: to.fullPath } });
    return;
  }

  // 需要管理员权限
  if (to.meta.requiresAdmin && (!user || user.role !== 'ADMIN')) {
    next({ name: 'Home' });
    return;
  }

  next();
});

export default router;
